35	const PROCESSING_FEE = 5;
36	
37	const BASE_PREMIUM: Record<string, number> = {
38	  sword: 100,
39	  amulet: 60,
40	  staff: 80,
41	  potion: 40,
42	  rune: 25,
43	  moonstone: 25,
44	};
45	
46	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
47	
48	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
49	const COMPONENT_BLOCK_SIZE = 3;
50	const COMPONENT_BLOCK_PRICE = 60;
51	
52	const groupByType = (items: Item[]): Map<string, Item[]> => {
53	  const groups = new Map<string, Item[]>();
54	  for (const item of items) {
55	    const group = groups.get(item.type) ?? [];
56	    group.push(item);
57	    groups.set(item.type, group);
58	  }
59	  return groups;
60	};
61	
62	const isHighlyEnchanted = (item: Item): boolean =>
63	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
64	
65	const itemSurchargeFactor = (item: Item): number =>
66	  (item.cursed ? CURSE_SURCHARGE : 0) +
67	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
68	
69	const itemModifiersFor = (item: Item): number =>
70	  basePremiumFor(item) * itemSurchargeFactor(item);
71	
72	const groupBaseCost = (type: string, group: Item[]): number => {
73	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
74	    return COMPONENT_BLOCK_PRICE;
75	  }
76	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
77	};
78	
79	const groupSubtotal = (type: string, group: Item[]): number =>
80	  groupBaseCost(type, group) +
81	  group.reduce((sum, item) => sum + itemModifiersFor(item), 0);
82	
83	const policyBase = (items: Item[]): number => {
84	  let total = 0;
85	  for (const [type, group] of groupByType(items)) {
86	    total += groupBaseCost(type, group);
87	  }
88	  return total;
89	};
90	
91	const itemSurchargesTotal = (items: Item[]): number =>
92	  items.reduce((sum, item) => sum + basePremiumFor(item) * itemSurchargeFactor(item), 0);
93	
94	const policyModifierFactor = (customer: { yearsWithMHPCO: number }): number =>
95	  FIRST_INSURANCE_SURCHARGE -
96	  (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT : 0);
97	
98	const quote = (
99	  items: Item[],
100	  customer: { yearsWithMHPCO: number },
101	): QuoteResult => {
102	  const base = policyBase(items);
103	  const itemSurcharges = itemSurchargesTotal(items);
104	  const policyModifiers = base * policyModifierFactor(customer);
105	  return {
106	    premium: Math.ceil(base + itemSurcharges + policyModifiers + PROCESSING_FEE),
107	  };
108	};
109	
110	export const runScenario = (scenario: Scenario): ScenarioResult => ({
111	  results: scenario.steps.map((step) => quote(step.items, scenario.customer)),
112	});
